def detect_tool_loop(tool_calls):
    signatures = []
    for tc in tool_calls:
        sig = (tc.function.name, hash(str(tc.function.arguments)))
        signatures.append(sig)

    if len(signatures) > 5:
        recent = signatures[-5:]
        if len(set(recent)) == 1:
            raise Exception('TOOL_LOOP: Repeated identical tool calls')
    tool_history.extend(signatures)

import time
class LoopDetector:
    def __init__(self):
        self.token_history = []
        self.start_time = time.time()

    def check(self, usage):
        self.token_history.append(usage.total_tokens)
        if len(self.token_history) > 10:
            avg_tokens = sum(self.token_history[-5:]) / 5
            if avg_tokens > 2000:  # High burn rate
                duration = time.time() - self.start_time
                if duration < 60 and sum(self.token_history[-5:]) > 10000:
                    print('TOOL_LOOP: Excessive token burn rate')

