failed_tools = set()
max_attempts = 3
attempts = defaultdict(int)

def safe_tool_call(tool_name, args):
    if tool_name in failed_tools:
        return {'error': 'TOOL_BLACKLISTED'}

    attempts[tool_name] += 1
    if attempts[tool_name] > max_attempts:
        failed_tools.add(tool_name)
        return {'error': 'MAX_ATTEMPTS_EXCEEDED'}

